INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'en', 'Tired of getting off a tour bus, snapping one photo, and getting back on? Tourgether lets you experience hidden gems only locals know, authentic restaurants, and the real vibe of each city. Connect directly with local guides and plan your own customized journey.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.title', 'en', 'Say goodbye to cookie-cutter package tours', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'en', 'Want to travel solo but worried about eating alone or having no one to take your photos? Use our "Open to Meet" feature to find other travelers in the same area. Share meals, tours, and activities with like-minded people and say goodbye to the loneliness of solo travel.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.title', 'en', 'A connection platform for solo travelers', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'en', 'No one knows your city better than you. Become a local guide on Tourgether, offer unique experiences to travelers, and earn income. Register various services like food tours, photography services, shopping companions, and language interpretation.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.title', 'en', 'A sharing economy where locals can earn', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'en', 'Trade with confidence using our escrow-based payment system. Funds are securely held until service completion, and our dispute resolution system protects both parties. Find trustworthy partners easily through reviews and verified host badges.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.title', 'en', 'Safe P2P transaction system', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'en', 'Share your travel moments with photos on the feed and visualize your journey on a map-based timeline. Our AI-powered CineMap feature analyzes photo location data to automatically create cinematic travel storyboards. Easily look back on your memories even after your trip.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.title', 'en', 'Beautifully preserve your travel memories', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.subtitle', 'en', 'A new way to rediscover the essence of travel', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.title', 'en', 'Why Tourgether?', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
